SELECT 'cell_definitions' AS t, COUNT(*) AS n FROM atlas.atlas_cell_definitions
UNION ALL SELECT 'cell_rule_candidates', COUNT(*) FROM atlas.atlas_cell_rule_candidates
UNION ALL SELECT 'conviction_daily', COUNT(*) FROM atlas.atlas_conviction_daily;

SELECT cap_tier, action, tenure, methodology_lock_ref, deprecated_at, validated_at
FROM atlas.atlas_cell_definitions
ORDER BY cap_tier, tenure, action;

SELECT version_num FROM atlas.atlas_alembic_version;
SELECT 'cell_definitions_active' AS t, COUNT(*) FROM atlas.atlas_cell_definitions WHERE deprecated_at IS NULL
UNION ALL SELECT 'cell_definitions_deprecated', COUNT(*) FROM atlas.atlas_cell_definitions WHERE deprecated_at IS NOT NULL
UNION ALL SELECT 'etf_scorecard_2026_05_22', COUNT(*) FROM information_schema.tables WHERE table_schema='atlas' AND table_name='atlas_etf_scorecard';

SELECT 'etf_scorecard' AS t, COUNT(*) AS n FROM atlas.atlas_etf_scorecard
UNION ALL SELECT 'fund_scorecard', COUNT(*) FROM atlas.atlas_fund_scorecard
UNION ALL SELECT 'alembic_version'::text, (SELECT version_num::int FROM atlas.atlas_alembic_version LIMIT 1);

SELECT table_name, column_name, data_type FROM information_schema.columns
WHERE table_schema='atlas' AND table_name IN (
  'atlas_etf_scorecard','atlas_fund_scorecard','atlas_universe_etfs','atlas_universe_funds',
  'atlas_universe_stocks','atlas_scorecard_daily','atlas_conviction_daily',
  'atlas_market_regime_daily','atlas_sector_states_daily'
) ORDER BY table_name, ordinal_position;

SELECT column_name, data_type FROM information_schema.columns
WHERE table_schema='atlas' AND table_name IN ('atlas_cell_definitions','atlas_cell_rule_candidates')
